// 5. EXPORTS
// ─────────────────────────────────────────────────────────────────────────────

module.exports = {
  DEFAULT_CAPABILITY_PATH,
  listRuntimeCapabilityIds,
  loadRuntimeCapabilities,
  resolveRuntimeCapability,
};
